    // Adaptive polling metrics
    MetricsKeySaturationEvents    = "sqs.worker_pool.saturation_events"
    MetricsKeySaturationDuration  = "sqs.worker_pool.saturation_duration"
    MetricsKeyPollingBackoff      = "sqs.consumer.polling_backoff"
    MetricsKeyAdaptiveAdjustments = "sqs.consumer.adaptive_adjustments"
)

// Add to initMetrics method
for eventType := range c.queueMap {
    // ... existing metrics ...

    // Adaptive polling metrics
    metrics.NewRegisteredCounter(fmt.Sprintf("%s.%s", MetricsKeySaturationEvents, eventType), registry)
    metrics.NewRegisteredTimer(fmt.Sprintf("%s.%s", MetricsKeySaturationDuration, eventType), registry)
    metrics.NewRegisteredCounter(fmt.Sprintf("%s.%s", MetricsKeyAdaptiveAdjustments, eventType), registry)
    metrics.NewRegisteredHistogram(fmt.Sprintf("%s.%s", MetricsKeyPollingBackoff, eventType), registry,
        metrics.NewExpDecaySample(1028, 0.015))
}

package sqsconsumer

import (
    "context"
    "testing"
    "time"

    "github.com/stretchr/testify/assert"
    "github.com/stretchr/testify/require"
)

func TestWorkerPool_HasAvailableWorkers(t *testing.T) {
    tests := []struct {
        name           string
        capacity       int
        activeWorkers  int
        closed         bool
        expected       bool
    }{
        {
            name:          "pool with available workers",
            capacity:      5,
            activeWorkers: 2,
            closed:        false,
            expected:      true,
        },
        {
            name:          "saturated pool",
            capacity:      5,
            activeWorkers: 5,
            closed:        false,
            expected:      false,
        },
        {
            name:          "closed pool",
            capacity:      5,
            activeWorkers: 0,
            closed:        true,
            expected:      false,
        },
    }

    for _, tt := range tests {
        t.Run(tt.name, func(t *testing.T) {
            pool := &WorkerPool{
                capacity:      tt.capacity,
                activeWorkers: int64(tt.activeWorkers),
                closed:        tt.closed,
            }

            result := pool.HasAvailableWorkers()
            assert.Equal(t, tt.expected, result)
        })
    }
}

func TestWorkerPool_GetAvailableCapacity(t *testing.T) {
    tests := []struct {
        name          string
        capacity      int
        activeWorkers int
        closed        bool
        expected      int
    }{
        {
            name:          "pool with available capacity",
            capacity:      10,
            activeWorkers: 3,
            closed:        false,
            expected:      7,
        },
        {
            name:          "saturated pool",
            capacity:      5,
            activeWorkers: 5,
            closed:        false,
            expected:      0,
        },
        {
            name:          "closed pool",
            capacity:      5,
            activeWorkers: 0,
            closed:        true,
            expected:      0,
        },
    }

    for _, tt := range tests {
        t.Run(tt.name, func(t *testing.T) {
            pool := &WorkerPool{
                capacity:      tt.capacity,
                activeWorkers: int64(tt.activeWorkers),
                closed:        tt.closed,
            }

            result := pool.GetAvailableCapacity()
            assert.Equal(t, tt.expected, result)
        })
    }
}
